import{_ as s,o as a,c as i,a2 as t}from"./chunks/framework.D5wUhsuj.js";const k=JSON.parse('{"title":"Migrating from Another Panel","description":"","frontmatter":{},"headers":[],"relativePath":"tutorials/migrating-from-other-panels.md","filePath":"tutorials/migrating-from-other-panels.md"}'),n={name:"tutorials/migrating-from-other-panels.md"};function l(r,e,h,o,d,p){return a(),i("div",null,[...e[0]||(e[0]=[t(`<h1 id="migrating-from-another-panel" tabindex="-1">Migrating from Another Panel <a class="header-anchor" href="#migrating-from-another-panel" aria-label="Permalink to &quot;Migrating from Another Panel&quot;">​</a></h1><p>If you&#39;re moving a site from cPanel, aaPanel, CloudPanel, Plesk, or a hand-configured server, the underlying files and databases move the same way regardless of which panel you&#39;re leaving. What differs is terminology and where things live. This page maps that, then walks through a real migration.</p><h2 id="terminology-map" tabindex="-1">Terminology map <a class="header-anchor" href="#terminology-map" aria-label="Permalink to &quot;Terminology map&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Concept</th><th>cPanel</th><th>aaPanel</th><th>CloudPanel</th><th>AidiPanel</th></tr></thead><tbody><tr><td>Add a site</td><td>&quot;Domain&quot; / &quot;Addon Domain&quot;</td><td>&quot;Add site&quot;</td><td>&quot;Add Site&quot;</td><td><code>site:add</code></td></tr><tr><td>Per-site OS user</td><td>cPanel account</td><td>usually shared <code>www</code> user</td><td>dedicated Site User</td><td>dedicated no-login Linux user (always, per-site)</td></tr><tr><td>Web root</td><td><code>~/public_html</code></td><td><code>/www/wwwroot/&lt;domain&gt;</code></td><td><code>/home/&lt;site-user&gt;/htdocs/&lt;domain&gt;</code></td><td><code>/home/&lt;site-user&gt;/htdocs/&lt;domain&gt;</code></td></tr><tr><td>PHP isolation</td><td>suEXEC / CloudLinux CageFS</td><td>shared PHP-FPM pool by default</td><td>per-site PHP-FPM pool</td><td>per-site PHP-FPM pool (always, not optional)</td></tr><tr><td>Page cache</td><td>plugin-based (LiteSpeed Cache, WP Super Cache)</td><td>plugin-based, or manual Nginx config</td><td>none built-in</td><td>Nginx FastCGI Cache, built in, per-site toggle</td></tr><tr><td>CLI</td><td>WHM API / <code>whmapi1</code></td><td><code>bt</code> command (limited)</td><td><code>clpctl</code></td><td><code>aidipanel</code></td></tr><tr><td>SSL</td><td>AutoSSL</td><td>one-click Let&#39;s Encrypt</td><td>one-click Let&#39;s Encrypt</td><td><code>ssl:install</code>, one-click, CLI or panel</td></tr></tbody></table><p>The biggest structural difference to internalize: <strong>on AidiPanel, per-site user + per-site PHP-FPM isolation is not a setting you turn on — it happens automatically on every <code>site:add</code>.</strong> If you&#39;re coming from aaPanel specifically, where PHP-FPM pools are commonly shared across sites unless manually separated, this is the one habit to unlearn — you don&#39;t need to (and can&#39;t) configure shared PHP for multiple sites here.</p><h2 id="pre-migration-checklist" tabindex="-1">Pre-migration checklist <a class="header-anchor" href="#pre-migration-checklist" aria-label="Permalink to &quot;Pre-migration checklist&quot;">​</a></h2><p>Before touching the new server, from your <strong>old</strong> server:</p><ul><li>[ ] Export each database: <code>mysqldump -u root -p dbname &gt; dbname.sql</code></li><li>[ ] Archive each site&#39;s files: <code>tar czf sitefiles.tar.gz -C /path/to/webroot .</code></li><li>[ ] Note down any custom <code>.htaccess</code> rules, cron jobs, and PHP <code>.ini</code> overrides — these don&#39;t migrate automatically</li><li>[ ] Note the site&#39;s current PHP version, so you can match it on the new server (or intentionally upgrade)</li><li>[ ] Lower your domain&#39;s DNS TTL to something short (300s / 5 min) a day or two ahead of the cutover, so the eventual DNS switch propagates fast</li></ul><h2 id="migration-steps" tabindex="-1">Migration steps <a class="header-anchor" href="#migration-steps" aria-label="Permalink to &quot;Migration steps&quot;">​</a></h2><h3 id="_1-create-the-site-on-aidipanel" tabindex="-1">1. Create the site on AidiPanel <a class="header-anchor" href="#_1-create-the-site-on-aidipanel" aria-label="Permalink to &quot;1. Create the site on AidiPanel&quot;">​</a></h3><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> site:add</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --domain</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example.com</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --user</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --type</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> php</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Use <code>php</code> when importing an existing WordPress installation. The <code>wordpress</code> type is for fresh atomic provisioning and requires the new site&#39;s title and administrator fields. Use <code>laravel</code>, <code>php</code>, or <code>static</code> for other existing applications as appropriate; see <a href="/docs/guide/sites#site-types">Site Management → Site Types</a>.</p><h3 id="_2-move-the-files" tabindex="-1">2. Move the files <a class="header-anchor" href="#_2-move-the-files" aria-label="Permalink to &quot;2. Move the files&quot;">​</a></h3><p>From your local machine (or directly server-to-server with <code>scp</code>):</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">scp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sitefiles.tar.gz</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root@new-server-ip:/home/example/htdocs/example.com/</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ssh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root@new-server-ip</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /home/example/htdocs/example.com</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">tar</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> xzf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sitefiles.tar.gz</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sitefiles.tar.gz</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chown</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -R</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example:example</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>That final <code>chown</code> is the step people most often forget coming from a panel where the web user was already the file owner by default — on AidiPanel, anything uploaded via <code>scp</code>/<code>root</code> needs to be handed off to the site&#39;s dedicated user explicitly.</p><h3 id="_3-create-the-database-and-import" tabindex="-1">3. Create the database and import <a class="header-anchor" href="#_3-create-the-database-and-import" aria-label="Permalink to &quot;3. Create the database and import&quot;">​</a></h3><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> db:add</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wp_example</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --user</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wp_example_user</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Save the generated password it prints</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mysql</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wp_example_user</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wp_example</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dbname.sql</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h3 id="_4-update-config-to-match-the-new-database" tabindex="-1">4. Update config to match the new database <a class="header-anchor" href="#_4-update-config-to-match-the-new-database" aria-label="Permalink to &quot;4. Update config to match the new database&quot;">​</a></h3><p>For WordPress, edit <code>wp-config.php</code>:</p><div class="language-php vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">php</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">define</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;DB_NAME&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;wp_example&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">define</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;DB_USER&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;wp_example_user&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">define</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;DB_PASSWORD&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;the-new-generated-password&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">define</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;DB_HOST&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;localhost&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>For Laravel, update the <code>DB_*</code> values in <code>.env</code> the same way — see <a href="/docs/tutorials/deploy-laravel#_3-configure-the-environment">Deploy a Laravel App, step 3</a>.</p><div class="tip custom-block"><p class="custom-block-title">WordPress site URL not matching?</p><p>If the old site used a different domain, or <code>http</code> vs <code>https</code>, update <code>siteurl</code> and <code>home</code> directly in the database rather than just in <code>wp-config.php</code>:</p><div class="language-sql vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">sql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">UPDATE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> wp_options </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">SET</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> option_value </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;https://example.com&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> WHERE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> option_name </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">IN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;siteurl&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;home&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></div><h3 id="_5-match-the-php-version-or-upgrade-deliberately" tabindex="-1">5. Match the PHP version (or upgrade deliberately) <a class="header-anchor" href="#_5-match-the-php-version-or-upgrade-deliberately" aria-label="Permalink to &quot;5. Match the PHP version (or upgrade deliberately)&quot;">​</a></h3><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> php:list</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> php:install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8.2</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # if the old site needs a version not installed yet</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> php:version</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --domain</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example.com</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --set</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8.2</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>If the old server was running something old like PHP 7.4, this is a natural moment to test on the <a href="/docs/guide/php">oldest version AidiPanel supports</a> rather than carrying legacy PHP forward — but test first, since very old codebases sometimes break on newer PHP major versions.</p><h3 id="_6-test-before-cutting-over-dns" tabindex="-1">6. Test before cutting over DNS <a class="header-anchor" href="#_6-test-before-cutting-over-dns" aria-label="Permalink to &quot;6. Test before cutting over DNS&quot;">​</a></h3><p>Before pointing the domain at the new server, confirm the site actually works using your local machine&#39;s hosts file so you&#39;re testing the real domain against the new server without affecting live traffic:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># /etc/hosts (or C:\\Windows\\System32\\drivers\\etc\\hosts on Windows)</span></span>
<span class="line"><span>&lt;new-server-ip&gt;  example.com</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>Visit <code>example.com</code> in your browser — you&#39;re now hitting the new server directly while everyone else still hits the old one. Check the homepage, an inner page, login, and any forms.</p><p>Remove that hosts file entry once you&#39;re satisfied.</p><h3 id="_7-cut-over-dns" tabindex="-1">7. Cut over DNS <a class="header-anchor" href="#_7-cut-over-dns" aria-label="Permalink to &quot;7. Cut over DNS&quot;">​</a></h3><p>Update the domain&#39;s <code>A</code> record at your DNS provider to the new server&#39;s IP. Since you lowered the TTL ahead of time (checklist above), this should propagate within minutes rather than hours.</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Watch propagation from the new server</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">watch</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 10</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;dig +short example.com&#39;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="_8-install-ssl-on-the-new-server" tabindex="-1">8. Install SSL on the new server <a class="header-anchor" href="#_8-install-ssl-on-the-new-server" aria-label="Permalink to &quot;8. Install SSL on the new server&quot;">​</a></h3><p>Only once DNS has actually switched:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ssl:install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --domain</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example.com</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --email</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> admin@example.com</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="_9-decommission-the-old-server" tabindex="-1">9. Decommission the old server <a class="header-anchor" href="#_9-decommission-the-old-server" aria-label="Permalink to &quot;9. Decommission the old server&quot;">​</a></h3><p>Once you&#39;ve confirmed the new site is stable (give it at least 24–48 hours), you can shut down the old one. Keep the database export and file archive around for a few weeks as a safety net regardless.</p><h2 id="common-migration-snags" tabindex="-1">Common migration snags <a class="header-anchor" href="#common-migration-snags" aria-label="Permalink to &quot;Common migration snags&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Symptom</th><th>Usual cause</th></tr></thead><tbody><tr><td>White screen after import</td><td>PHP version mismatch, or a plugin/extension available on the old host but not installed here</td></tr><tr><td>&quot;Error establishing a database connection&quot;</td><td><code>wp-config.php</code> / <code>.env</code> still has the <em>old</em> server&#39;s DB credentials</td></tr><tr><td>Uploads/images broken</td><td>File ownership wasn&#39;t fixed with <code>chown</code> after transfer — PHP can&#39;t write, and old absolute URLs may still point at the old domain</td></tr><tr><td>Site loads but assets (CSS/JS) are missing</td><td>Old site used absolute URLs baked into the database pointing at the old domain — see the <code>siteurl</code>/<code>home</code> tip above, and search-replace the domain across the DB if this was a domain change too</td></tr></tbody></table><p>For anything not covered here, the general <a href="/docs/troubleshooting/">Troubleshooting</a> index is organized by symptom rather than by cause, which tends to be faster when you&#39;re not sure what&#39;s actually wrong yet.</p>`,42)])])}const g=s(n,[["render",l]]);export{k as __pageData,g as default};
